// 오늘 날짜 기반으로 생성할 리포트 타입 결정
const today = new Date();
const month = today.getMonth() + 1; // 1-12

const periodTypes = ['quarterly']; // 항상 분기 리포트
if (month === 1 || month === 7) periodTypes.push('half_year'); // 7월, 1월
if (month === 1) periodTypes.push('annual'); // 1월만 연간

// 각 period_type에 대한 기간 계산
const periods = periodTypes.map(type => {
  let periodStart, periodEnd, months, label;

  if (type === 'quarterly') {
    months = 3;
    label = `${today.getFullYear()}년 Q${Math.ceil((month - 1) / 3)}분기`;
    periodStart = new Date(today.getFullYear(), today.getMonth() - 3, 1);
    periodEnd   = new Date(today.getFullYear(), today.getMonth(), 0);
  } else if (type === 'half_year') {
    months = 6;
    label = month === 1 ? `${today.getFullYear() - 1}년 하반기` : `${today.getFullYear()}년 상반기`;
    periodStart = new Date(today.getFullYear(), today.getMonth() - 6, 1);
    periodEnd   = new Date(today.getFullYear(), today.getMonth(), 0);
  } else if (type === 'annual') {
    months = 12;
    label = `${today.getFullYear() - 1}년 연간`;
    periodStart = new Date(today.getFullYear() - 1, 0, 1);
    periodEnd   = new Date(today.getFullYear() - 1, 11, 31);
  }

  return {
    period_type: type,
    period_start_iso: periodStart.toISOString(),
    period_end_iso:   periodEnd.toISOString(),
    label,
    months
  };
});

return periods.map(p => ({ json: p }));

// 장기 집계 통계 계산 및 LLM 프롬프트 생성
const items = $input.all();
const periodInfo = $('리포트 타입별 반복').first().json;

if (!items.length) {
  return [{ json: { skip: true, ...periodInfo } }];
}

const systemSummary = {};
items.forEach(item => {
  const d = item.json;
  if (!systemSummary[d.system_name]) {
    systemSummary[d.system_name] = {
      system_id: d.system_id,
      display_name: d.display_name,
      total_anomaly_hours: 0,
      worst_severity: 'normal',
      trends: []
    };
  }
  const s = systemSummary[d.system_name];
  s.total_anomaly_hours += parseFloat(d.total_anomaly_hours) || 0;
  if (d.worst_severity === 'critical' || (d.worst_severity === 'warning' && s.worst_severity !== 'critical')) {
    s.worst_severity = d.worst_severity;
  }
  if (d.trend_summary) s.trends.push(d.trend_summary.substring(0, 80));
});

const systemLines = Object.values(systemSummary)
  .sort((a, b) => b.total_anomaly_hours - a.total_anomaly_hours)
  .slice(0, 8)
  .map(s => `- ${s.display_name}: 이상 ${Math.round(s.total_anomaly_hours)}시간, 심각도: ${s.worst_severity}`);

const periodLabel = periodInfo.label;
const llmPrompt = `${periodLabel} 전체 시스템 모니터링 ${periodInfo.period_type === 'quarterly' ? '분기' : periodInfo.period_type === 'half_year' ? '반기' : '연간'} 집계입니다.

[시스템별 현황]
${systemLines.join('\n')}

총 ${Object.keys(systemSummary).length}개 시스템. 이 기간의 전반적인 시스템 안정성 평가, 개선된 점, 우려되는 장기 추세, 향후 권고사항을 한국어로 4-5 문장으로 요약해 주세요.`;

const metricsJson = JSON.stringify({
  period: periodLabel,
  period_type: periodInfo.period_type,
  system_count: Object.keys(systemSummary).length,
  total_anomaly_hours: Math.round(Object.values(systemSummary).reduce((a, s) => a + s.total_anomaly_hours, 0)),
  critical_systems: Object.values(systemSummary).filter(s => s.worst_severity === 'critical').length
});

return [{
  json: {
    ...periodInfo,
    llm_prompt: llmPrompt,
    metrics_json: metricsJson,
    system_count: Object.keys(systemSummary).length,
    skip: false
  }
}];

const llmResp = $input.first().json;
const prevData = $('장기 집계 계산 및 LLM 프롬프트 생성').first().json;

const llmSummary = llmResp?.choices?.[0]?.message?.content 
  || llmResp?.response 
  || llmResp?.content 
  || '장기 요약 생성 실패';

const metricsObj = JSON.parse(prevData.metrics_json || '{}');
const periodEmoji = prevData.period_type === 'annual' ? '🗓️' : prevData.period_type === 'half_year' ? '📆' : '📊';

const card = {
  type: 'message',
  attachments: [{
    contentType: 'application/vnd.microsoft.card.adaptive',
    content: {
      '$schema': 'http://adaptivecards.io/schemas/adaptive-card.json',
      type: 'AdaptiveCard',
      version: '1.4',
      body: [
        { type: 'TextBlock', text: `${periodEmoji} ${prevData.label} 모니터링 리포트`, weight: 'Bolder', size: 'Medium' },
        { type: 'TextBlock', text: llmSummary, wrap: true },
        {
          type: 'FactSet',
          facts: [
            { title: '기간',            value: `${prevData.period_start_iso.split('T')[0]} ~ ${prevData.period_end_iso.split('T')[0]}` },
            { title: '모니터링 시스템', value: `${metricsObj.system_count || 0}개` },
            { title: '총 이상 발생',    value: `${metricsObj.total_anomaly_hours || 0}시간` },
            { title: 'Critical 시스템', value: `${metricsObj.critical_systems || 0}개` }
          ]
        }
      ]
    }
  }]
};

return [{ json: { ...prevData, llm_summary: llmSummary, teams_card: JSON.stringify(card) } }];
